import { Hono } from 'hono';
import { PrismaClient } from '@prisma/client';

const app = new Hono();
const prisma = new PrismaClient();

app.post('/archive', async (c) => {
  try {
    const thirtyDaysAgo = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000);

    await prisma.$transaction(async (tx) => {
      // Move finished tasks older than 30 days to archived_tasks table
      await tx.task.updateMany({
        where: {
          status: 'finished',
          createdAt: { lt: thirtyDaysAgo },
        },
        data: {
          status: 'archived',
        },
      });

      // Insert the moved tasks into the archived_tasks table
      const archivedTasks = await tx.task.findMany({
        where: {
          status: 'archived',
        },
      });

      for (const task of archivedTasks) {
        await tx.archivedTask.create({
          data: {
            taskId: task.id,
            title: task.title,
            description: task.description,
            createdAt: task.createdAt,
            updatedAt: task.updatedAt,
            status: task.status,
          },
        });
      }

      // Delete the tasks from the original table
      await tx.task.deleteMany({
        where: {
          status: 'archived',
        },
      });
    });

    return c.json({ message: 'Tasks archived successfully' }, 200);
  } catch (error) {
    console.error('Error archiving tasks:', error);
    return c.json({ error: 'Failed to archive tasks' }, 500);
  }
});

export default app;

